(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>\"]/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"volumetric-weight",fields:[{"key":"lengthCm","label":"길이 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"widthCm","label":"너비 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"heightCm","label":"높이 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"divisor","label":"부피무게 나눗값","type":"number","placeholder":"","default":"5000","options":[],"raw":false}],hint:"운송사와 운송수단에 따라 적용하는 나눗값이 다릅니다.",compute:function(x){var l=Number(x.lengthCm),w=Number(x.widthCm),h=Number(x.heightCm),d=Number(x.divisor);if(![l,w,h,d].every(Number.isFinite)||l<=0||w<=0||h<=0||d<=0)return{error:"상자 치수와 나눗값은 0보다 크게 입력해 주세요."};var cm3=l*w*h;return{volumetricWeightKg:cm3/d,volumeLiters:cm3/1000,volumeCm3:cm3};},format:function(r,api){return api.resultCard("부피무게",api.formatNumber(r.volumetricWeightKg,3)+"kg","운송사별 나눗값 확인")+api.resultCard("상자 부피",api.formatNumber(r.volumeLiters,3)+"L",api.formatNumber(r.volumeCm3,0)+"cm³");}},{id:"carton-fill-rate",fields:[{"key":"lengthCm","label":"상자 길이 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"widthCm","label":"상자 너비 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"heightCm","label":"상자 높이 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"itemVolumeLiters","label":"포장물 총부피 (L)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var l=Number(x.lengthCm),w=Number(x.widthCm),h=Number(x.heightCm),v=Number(x.itemVolumeLiters);if(![l,w,h,v].every(Number.isFinite)||l<=0||w<=0||h<=0||v<0)return{error:"상자 치수는 0보다 크게, 포장물 부피는 0 이상으로 입력해 주세요."};var box=l*w*h/1000;if(v>box)return{error:"포장물 총부피가 상자 부피보다 큽니다."};return{boxVolumeLiters:box,fillRate:v/box*100,unusedVolumeLiters:box-v};},format:function(r,api){return api.resultCard("공간 충전율",api.formatNumber(r.fillRate,2)+"%","상자 "+api.formatNumber(r.boxVolumeLiters,2)+"L")+api.resultCard("빈 공간",api.formatNumber(r.unusedVolumeLiters,2)+"L","");}},{id:"pallet-box-count",fields:[{"key":"palletLengthCm","label":"팔레트 길이 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"palletWidthCm","label":"팔레트 너비 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"boxLengthCm","label":"상자 길이 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"boxWidthCm","label":"상자 너비 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"layers","label":"적재 층수","type":"integer","placeholder":"","default":"1","options":[],"raw":false}],hint:"혼합 배치, 돌출 허용, 하중과 안정성은 반영하지 않은 직사각 격자 계산입니다.",compute:function(x){var pl=Number(x.palletLengthCm),pw=Number(x.palletWidthCm),bl=Number(x.boxLengthCm),bw=Number(x.boxWidthCm),n=Number(x.layers);if(![pl,pw,bl,bw,n].every(Number.isFinite)||pl<=0||pw<=0||bl<=0||bw<=0||!Number.isInteger(n)||n<=0)return{error:"치수는 0보다 크게, 층수는 0보다 큰 정수로 입력해 주세요."};var a=Math.floor(pl/bl)*Math.floor(pw/bw),b=Math.floor(pl/bw)*Math.floor(pw/bl),per=Math.max(a,b);return{orientationA:a,orientationB:b,boxesPerLayer:per,totalBoxes:per*n};},format:function(r,api){return api.resultCard("층당 최대 상자",api.formatNumber(r.boxesPerLayer,0)+"개","방향별 "+r.orientationA+"개 / "+r.orientationB+"개")+api.resultCard("전체 적재량",api.formatNumber(r.totalBoxes,0)+"개","");}},{id:"container-item-capacity",fields:[{"key":"containerVolumeM3","label":"컨테이너 내부 부피 (m³)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"itemVolumeM3","label":"물품 1개 부피 (m³)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"utilizationPercent","label":"목표 공간 활용률 (%)","type":"number","placeholder":"","default":"85","options":[],"raw":false}],hint:"실제 적재는 물품 형상, 방향, 하중, 포장 여유에 따라 달라집니다.",compute:function(x){var c=Number(x.containerVolumeM3),i=Number(x.itemVolumeM3),u=Number(x.utilizationPercent);if(![c,i,u].every(Number.isFinite)||c<=0||i<=0||u<0||u>100)return{error:"컨테이너와 물품 부피는 0보다 크게, 활용률은 0~100%로 입력해 주세요."};var usable=c*u/100,count=Math.floor(usable/i);return{usableVolumeM3:usable,itemCount:count,usedVolumeM3:count*i,unusedVolumeM3:c-count*i};},format:function(r,api){return api.resultCard("이론상 적재 개수",api.formatNumber(r.itemCount,0)+"개","활용 가능 부피 "+api.formatNumber(r.usableVolumeM3,3)+"m³")+api.resultCard("전체 남는 부피",api.formatNumber(r.unusedVolumeM3,3)+"m³","");}},{id:"shipping-chargeable-weight",fields:[{"key":"actualWeightKg","label":"실중량 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"volumetricWeightKg","label":"부피무게 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"ratePerKg","label":"kg당 운임","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"baseFee","label":"기본요금","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.actualWeightKg),v=Number(x.volumetricWeightKg),r=Number(x.ratePerKg),b=Number(x.baseFee);if(![a,v,r,b].every(Number.isFinite)||a<0||v<0||r<0||b<0)return{error:"중량·운임·기본요금은 0 이상으로 입력해 주세요."};var charge=Math.max(a,v),cost=b+charge*r;return{chargeableWeightKg:charge,shippingCost:cost,weightDifference:Math.abs(a-v)};},format:function(r,api){return api.resultCard("청구무게",api.formatNumber(r.chargeableWeightKg,3)+"kg","두 중량 차이 "+api.formatNumber(r.weightDifference,3)+"kg")+api.resultCard("예상 운임",api.formatMoney(r.shippingCost),"");}},{id:"sheet-roll-length",fields:[{"key":"outerDiameterMm","label":"롤 외경 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"coreDiameterMm","label":"코어 지름 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"thicknessMm","label":"재료 두께 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"압축, 공기층, 장력, 두께 편차는 반영하지 않은 이론값입니다.",compute:function(x){var d=Number(x.outerDiameterMm),c=Number(x.coreDiameterMm),t=Number(x.thicknessMm);if(![d,c,t].every(Number.isFinite)||d<=0||c<0||c>=d||t<=0)return{error:"롤 외경과 두께는 0보다 크게, 코어 지름은 롤 외경보다 작게 입력해 주세요."};var lengthMm=Math.PI*(d*d-c*c)/(4*t);return{lengthM:lengthMm/1000,lengthKm:lengthMm/1000000,materialAreaM2:lengthMm/1000*d/1000};},format:function(r,api){return api.resultCard("추정 롤 길이",api.formatNumber(r.lengthM,3)+"m",api.formatNumber(r.lengthKm,6)+"km")+api.resultCard("참고", "균일한 두께·빈틈 없는 권취 가정","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
